//! Round-trip property tests (Epic 23.1).
//!
//! Verifies that `serialize(build(…))` → `Platform::with_all_profiles().parse(bytes)` preserves the
//! observable message properties: type, Pruefidentifikator, release code.
//!
//! The test corpus is generated by `proptest`, which tries many random
//! input combinations and shrinks failures automatically.

// All *_RELEASES constants and top-level imports are used exclusively inside
// feature-gated test modules; they carry individual #[allow(dead_code)] /
// #[allow(unused_imports)] annotations below.

// Items used via `use super::*` inside feature-gated test modules.
#[allow(unused_imports)]
use edi_energy::{
    AnyMessage, EdiEnergyMessage, MessageType, ObjectType, Platform, Pruefidentifikator, Release,
};

// ── Helpers ───────────────────────────────────────────────────────────────────

/// Known UTILMD release codes used in the German energy market.
///
/// Classic 5.5.x releases are **parse-capable** (the EDIFACT wire format is
/// the same) but have **no registered profiles** — `validate()` returns
/// `Error::ProfileNotFound` for them.  They are included here to verify that
/// the serialize→parse round-trip preserves the wire release code even when
/// no validation profile exists.
#[cfg(feature = "utilmd")]
const UTILMD_RELEASES: &[&str] = &[
    "5.5.3a", "5.5.4a", "5.5.5a", "5.5.6a", "5.5.7a", "5.5.8a", "S2.1", "S2.2",
];

/// Known MSCONS release codes (wire assoc_codes from registered profiles).
#[cfg(feature = "mscons")]
const MSCONS_RELEASES: &[&str] = &["2.4c", "2.5"];

/// Known APERAK release codes.
#[cfg(feature = "aperak")]
const APERAK_RELEASES: &[&str] = &["2.0a", "2.0b", "2.0c", "2.1a", "2.1i", "2.2"];

/// Known CONTRL release codes.
#[cfg(feature = "contrl")]
const CONTRL_RELEASES: &[&str] = &["1.0a", "1.0b", "2.0a", "2.0b"];

// ── UTILMD round-trip ─────────────────────────────────────────────────────────

#[cfg(feature = "utilmd")]
mod utilmd_roundtrip {
    use super::*;
    use edi_energy::builders::UtilmdBuilder;
    use proptest::prelude::*;

    proptest! {
        /// For any valid Pruefidentifikator in 10_000–99_999, a UTILMD message
        /// built and serialized must re-parse to the same type and same PID.
        #[test]
        fn utilmd_pid_survives_roundtrip(
            pid_u32 in 10_000u32..=99_999,
            release_idx in 0usize..UTILMD_RELEASES.len(),
            sender in "[0-9]{13}",
            receiver in "[0-9]{13}",
        ) {
            let pid = Pruefidentifikator::new(pid_u32).unwrap();
            let release = Release::new(UTILMD_RELEASES[release_idx]);

            let bytes = UtilmdBuilder::new(release.clone())
                .pruefidentifikator(pid)
                .sender(sender.as_str())
                .receiver(receiver.as_str())
                .serialize()
                .expect("serialize must not fail for valid inputs");

            let reparsed = Platform::with_all_profiles().parse(&bytes)
                .expect("serialized UTILMD must re-parse without errors");

            prop_assert_eq!(reparsed.try_message_type(), Some(MessageType::Utilmd));

            let reparsed_pid = reparsed.detect_pruefidentifikator()
                .expect("re-parsed UTILMD must carry a Pruefidentifikator");
            prop_assert_eq!(reparsed_pid.as_u32(), pid_u32);

            let reparsed_release = reparsed.detect_release()
                .expect("re-parsed UTILMD must carry a release code");
            prop_assert_eq!(reparsed_release.as_str(), release.as_str());
        }

        /// Message reference is preserved across a round-trip.
        #[test]
        fn utilmd_message_ref_survives_roundtrip(
            msg_ref in "[A-Z0-9]{1,14}",
        ) {
            use edi_energy::builders::UtilmdBuilder;
            use edi_energy::AnyMessage;
            let pid = Pruefidentifikator::new(11001).unwrap();
            let bytes = UtilmdBuilder::new(Release::new("5.5.3a"))
                .pruefidentifikator(pid)
                .sender("4012345000023")
                .receiver("9900357000004")
                .message_ref(msg_ref.as_str())
                .serialize()
                .expect("serialize must not fail");

            let reparsed = Platform::with_all_profiles().parse(&bytes).expect("must re-parse");
            prop_assert_eq!(reparsed.try_message_type(), Some(MessageType::Utilmd));

            // message_ref() carries the UNH reference number — downcast to typed message
            if let AnyMessage::Utilmd(utilmd) = reparsed {
                prop_assert_eq!(utilmd.message_ref(), msg_ref.as_str());
            } else {
                panic!("expected Utilmd variant");
            }
        }
    }
}

// ── MSCONS round-trip ─────────────────────────────────────────────────────────

#[cfg(feature = "mscons")]
mod mscons_roundtrip {
    use super::*;
    use edi_energy::builders::MsconsBuilder;
    use proptest::prelude::*;

    proptest! {
        /// For any valid MSCONS PID, a built-and-serialized message must
        /// re-parse with the same type and PID.
        #[test]
        fn mscons_pid_survives_roundtrip(
            pid_u32 in 10_000u32..=99_999,
            release_idx in 0usize..MSCONS_RELEASES.len(),
        ) {
            let pid = Pruefidentifikator::new(pid_u32).unwrap();
            let release = Release::new(MSCONS_RELEASES[release_idx]);

            let bytes = MsconsBuilder::new(release.clone())
                .pruefidentifikator(pid)
                .sender("4012345000023")
                .receiver("9900357000004")
                .serialize()
                .expect("serialize must not fail for valid inputs");

            let reparsed = Platform::with_all_profiles().parse(&bytes)
                .expect("serialized MSCONS must re-parse without errors");

            prop_assert_eq!(reparsed.try_message_type(), Some(MessageType::Mscons));

            let reparsed_pid = reparsed.detect_pruefidentifikator()
                .expect("re-parsed MSCONS must carry a Pruefidentifikator");
            prop_assert_eq!(reparsed_pid.as_u32(), pid_u32);

            let reparsed_release = reparsed.detect_release().expect("must have release");
            prop_assert_eq!(reparsed_release.as_str(), release.as_str());

            // validate() must not panic. Bare messages (no UNB envelope)
            // always return a Parse error; registered PIDs may return Ok or
            // ProfileNotFound. Any of these outcomes are acceptable here.
            let _validation_result = reparsed.validate();
        }

        /// Metering point data survives serialization: location IDs and OBIS
        /// codes must appear verbatim in the serialized bytes.
        #[test]
        fn mscons_metering_point_data_in_bytes(
            malo_id in "DE[0-9]{11}",
            obis in "[0-9]{1,2}-[0-9]{1,2}:[1-9][0-9]?\\.[0-9]{1,2}\\.[0-9]{1,2}",
            quantity in "[0-9]{1,8}",
        ) {
            let bytes = MsconsBuilder::new(Release::new("2.4c"))
                .pruefidentifikator(Pruefidentifikator::new(13003).unwrap())
                .sender("4012345000023")
                .receiver("9900357000004")
                .metering_point(malo_id.as_str())
                .obis(rubo4e::identifiers::ObisCode::new(obis.as_str()).expect("proptest regex ensures valid OBIS"))
                .quantity("220", quantity.as_str(), "KWH")
                .done()
                .serialize()
                .expect("serialize must not fail");

            // malo_id and obis must be present in the output
            let output = String::from_utf8(bytes).expect("serialized output must be valid UTF-8");
            prop_assert!(
                output.contains(malo_id.as_str()),
                "malo_id {malo_id} not found in output"
            );
        }
    }
}

