// ── CONTRL round-trip ─────────────────────────────────────────────────────────

#[cfg(feature = "contrl")]
mod contrl_roundtrip {
    use super::*;
    use edi_energy::builders::ContrlBuilder;
    use proptest::prelude::*;

    proptest! {
        /// A built CONTRL message with any valid release must re-parse as CONTRL.
        #[test]
        fn contrl_survives_roundtrip(
            release_idx in 0usize..CONTRL_RELEASES.len(),
            accept in proptest::bool::ANY,
        ) {
            let release = Release::new(CONTRL_RELEASES[release_idx]);
            let builder = ContrlBuilder::new(release.clone())
                .sender("4012345000023")
                .receiver("9900357000004")
                .interchange_ref("REF001");

            let builder = if accept { builder.accept() } else { builder.reject() };

            let bytes = builder.serialize().expect("serialize must not fail");
            let reparsed = Platform::with_all_profiles().parse(&bytes).expect("serialized CONTRL must re-parse");

            prop_assert_eq!(reparsed.try_message_type(), Some(MessageType::Contrl));
            let reparsed_release = reparsed.detect_release().expect("must have release");
            prop_assert_eq!(reparsed_release.as_str(), release.as_str());
        }
    }
}

// ── Charset invariant ─────────────────────────────────────────────────────────

/// Any builder-generated message must produce only EDIFACT-safe ASCII bytes.
#[allow(dead_code)] // called from multiple feature-gated test modules
fn assert_edifact_charset(bytes: &[u8], label: &str) {
    for (i, &b) in bytes.iter().enumerate() {
        assert!(
            b == b'\t' || b == b'\n' || b == b'\r' || (0x20..=0x7e).contains(&b),
            "byte {b:#04x} at offset {i} in {label} is outside EDIFACT-safe ASCII range"
        );
    }
}

#[cfg(feature = "utilmd")]
mod charset_invariant {
    use super::*;
    use edi_energy::builders::UtilmdBuilder;
    use proptest::prelude::*;

    proptest! {
        /// Builder-generated UTILMD must produce clean ASCII for any valid PID.
        #[test]
        fn utilmd_bytes_are_ascii_safe(pid_u32 in 10_000u32..=99_999) {
            let pid = Pruefidentifikator::new(pid_u32).unwrap();
            let bytes = UtilmdBuilder::new(Release::new("5.5.3a"))
                .pruefidentifikator(pid)
                .sender("4012345000023")
                .receiver("9900357000004")
                .serialize()
                .expect("serialize must not fail");
            assert_edifact_charset(&bytes, "UTILMD");
            assert!(!bytes.contains(&0u8), "no null bytes");
        }
    }
}

// ── UTILMD S2.1/S2.2 transaction builder ─────────────────────────────────────

#[cfg(feature = "utilmd")]
mod utilmd_transaction_tests {
    use super::*;
    use edi_energy::{AnyMessage, builders::UtilmdBuilder};

    /// A UTILMD S2.1 message with a transaction block (SG4/IDE) must round-trip
    /// correctly: the IDE qualifier, location ID, status, and references survive
    /// serialization and re-parsing.
    #[test]
    fn utilmd_s21_transaction_roundtrip() {
        let pid = Pruefidentifikator::new(55001).unwrap();
        let bytes = UtilmdBuilder::new(Release::new("S2.1"))
            .pruefidentifikator(pid)
            .document_code("E01")
            .sender("4012345000023")
            .receiver("9900357000004")
            .document_date("20241101")
            .transaction(ObjectType::Messlokation, "DE00012345678")
            .process_date("163", "20241101")
            .reference("Z13", "55001")
            .done()
            .serialize()
            .expect("S2.1 message with transaction must serialize");

        let reparsed = Platform::with_all_profiles()
            .parse(&bytes)
            .expect("must re-parse");
        assert_eq!(reparsed.try_message_type(), Some(MessageType::Utilmd));

        let AnyMessage::Utilmd(u) = reparsed else {
            panic!("expected Utilmd")
        };
        assert_eq!(u.assoc_code(), "S2.1");

        // Transaction block must be extractable
        assert_eq!(u.transactions().len(), 1, "one transaction expected");
        let tx = &u.transactions()[0];
        assert_eq!(tx.ide.qualifier, "Z19");
        assert_eq!(tx.ide.object_id.as_deref(), Some("DE00012345678"));
        assert!(!tx.dtm.is_empty(), "process DTM must be captured");
        assert!(
            tx.references.iter().any(|r| r.qualifier == "Z13"),
            "Z13 Pruefidentifikator reference must survive roundtrip"
        );
    }

    /// UTILMD S2.1 Sperrung (PID 55555) with STS segment: status must be
    /// extractable after roundtrip.
    #[test]
    fn utilmd_s21_sperrung_sts_roundtrip() {
        let pid = Pruefidentifikator::new(55555).unwrap();
        let bytes = UtilmdBuilder::new(Release::new("S2.1"))
            .pruefidentifikator(pid)
            .document_code("E03")
            .sender("4012345000023")
            .receiver("9900357000004")
            .transaction(ObjectType::Messlokation, "DE00012345678")
            .status("E07")
            .reference("Z13", "55555")
            .done()
            .serialize()
            .expect("S2.1 Sperrung must serialize");

        let reparsed = Platform::with_all_profiles()
            .parse(&bytes)
            .expect("must re-parse");
        let AnyMessage::Utilmd(u) = reparsed else {
            panic!("expected Utilmd")
        };

        let tx = &u.transactions()[0];
        assert_eq!(tx.sts.len(), 1, "STS segment must be captured");
        assert_eq!(tx.sts[0].category.as_deref(), Some("E07"));
    }

    /// UTILMD S2.2 message — structurally identical to S2.1, different assoc_code.
    #[test]
    fn utilmd_s22_transaction_roundtrip() {
        let pid = Pruefidentifikator::new(55001).unwrap();
        let bytes = UtilmdBuilder::new(Release::new("S2.2"))
            .pruefidentifikator(pid)
            .sender("4012345000023")
            .receiver("9900357000004")
            .transaction(ObjectType::Marktlokation, "12345678901")
            .reference("Z13", "55001")
            .done()
            .serialize()
            .expect("S2.2 message must serialize");

        let reparsed = Platform::with_all_profiles()
            .parse(&bytes)
            .expect("must re-parse");
        let AnyMessage::Utilmd(u) = reparsed else {
            panic!("expected Utilmd")
        };
        assert_eq!(u.assoc_code(), "S2.2");
        assert_eq!(u.transactions()[0].ide.qualifier, "Z18");
    }

    /// Multiple transactions in a single message must all be captured.
    #[test]
    fn utilmd_s21_multiple_transactions() {
        let bytes = UtilmdBuilder::new(Release::new("S2.1"))
            .sender("4012345000023")
            .receiver("9900357000004")
            .transaction(ObjectType::Messlokation, "DE00000000001")
            .reference("Z13", "55001")
            .done()
            .transaction(ObjectType::Messlokation, "DE00000000002")
            .reference("Z13", "55001")
            .done()
            .transaction(ObjectType::Messlokation, "DE00000000003")
            .reference("Z13", "55002")
            .done()
            .serialize()
            .expect("multi-transaction S2.1 must serialize");

        let reparsed = Platform::with_all_profiles()
            .parse(&bytes)
            .expect("must re-parse");
        let AnyMessage::Utilmd(u) = reparsed else {
            panic!("expected Utilmd")
        };
        assert_eq!(
            u.transactions().len(),
            3,
            "all three transactions must be captured"
        );
        assert_eq!(
            u.transactions()[0].ide.object_id.as_deref(),
            Some("DE00000000001")
        );
        assert_eq!(
            u.transactions()[2].ide.object_id.as_deref(),
            Some("DE00000000003")
        );
    }
}

// ── IFTSTA round-trip ─────────────────────────────────────────────────────────

/// Known IFTSTA release codes — one per registered fv-dated profile plus legacy.
#[cfg(feature = "iftsta")]
const IFTSTA_RELEASES: &[&str] = &["2.0g", "2.1"];

#[cfg(feature = "iftsta")]
mod iftsta_roundtrip {
    use super::*;
    use edi_energy::builders::IftstaBuilder;

    /// For each IFTSTA release, a message built with IftstaBuilder must
    /// re-parse to the same message type and assoc_code.
    #[test]
    fn iftsta_survives_roundtrip() {
        for &release_str in IFTSTA_RELEASES {
            let release = Release::new(release_str);
            let bytes = IftstaBuilder::new(release.clone())
                .sender("4012345000023")
                .receiver("9900357000004")
                .document_id("00021000")
                .serialize()
                .expect("IftstaBuilder serialize must not fail");

            let msg = Platform::with_all_profiles()
                .parse(&bytes)
                .expect("re-parse must succeed");
            let AnyMessage::Iftsta(m) = msg else {
                panic!("expected Iftsta for release {release_str}");
            };
            assert_eq!(
                m.assoc_code(),
                release_str,
                "assoc_code must survive round-trip for release {release_str}"
            );
            assert_eq!(
                m.sender().unwrap().party_id.as_deref(),
                Some("4012345000023"),
                "sender must survive round-trip"
            );
        }
    }

    /// Both release variants must parse identically as IftstaMessage;
    /// the only observable difference is assoc_code.
    #[test]
    fn iftsta_20g_vs_21_same_structure() {
        let bytes_20g = IftstaBuilder::new(Release::new("2.0g"))
            .sender("4012345000023")
            .receiver("9900357000004")
            .serialize()
            .unwrap();
        let bytes_21 = IftstaBuilder::new(Release::new("2.1"))
            .sender("4012345000023")
            .receiver("9900357000004")
            .serialize()
            .unwrap();

        let AnyMessage::Iftsta(m1) = Platform::with_all_profiles().parse(&bytes_20g).unwrap()
        else {
            panic!()
        };
        let AnyMessage::Iftsta(m2) = Platform::with_all_profiles().parse(&bytes_21).unwrap() else {
            panic!()
        };

        assert_eq!(m1.assoc_code(), "2.0g");
        assert_eq!(m2.assoc_code(), "2.1");
        // Both have the same sender/receiver — only wire code differs
        assert_eq!(m1.sender(), m2.sender());
        assert_eq!(m1.receiver(), m2.receiver());
    }
}

// ── INSRPT round-trip ─────────────────────────────────────────────────────────

/// Known INSRPT release codes — one wire release "1.1a" shared by both fv-dated profiles.
#[cfg(feature = "insrpt")]
const INSRPT_RELEASES: &[&str] = &["1.1a"];

#[cfg(feature = "insrpt")]
mod insrpt_roundtrip {
    use super::*;
    use edi_energy::builders::InsrptBuilder;

    /// For each INSRPT release, a message built with InsrptBuilder must
    /// re-parse to the same message type and assoc_code.
    #[test]
    fn insrpt_survives_roundtrip() {
        for &release_str in INSRPT_RELEASES {
            let release = Release::new(release_str);
            let bytes = InsrptBuilder::new(release.clone())
                .sender("4012345000023")
                .receiver("9900357000004")
                .document_id("BEP00021000")
                .serialize()
                .expect("InsrptBuilder serialize must not fail");

            let msg = Platform::with_all_profiles()
                .parse(&bytes)
                .expect("re-parse must succeed");
            let AnyMessage::Insrpt(m) = msg else {
                panic!("expected Insrpt for release {release_str}");
            };
            assert_eq!(
                m.assoc_code(),
                release_str,
                "assoc_code must survive round-trip for release {release_str}"
            );
            assert_eq!(
                m.sender().unwrap().party_id.as_deref(),
                Some("4012345000023"),
                "sender must survive round-trip"
            );
        }
    }

    /// INSRPT uses the same wire code "1.1a" for both fv-dated profiles;
    /// verify that the builder produces a parseable InsrptMessage for both.
    #[test]
    fn insrpt_both_fv_dates_same_wire_code() {
        // fv20211001 and fv20260101 both use wire code "1.1a"
        let bytes1 = InsrptBuilder::new(Release::new("1.1a"))
            .sender("4012345000023")
            .receiver("9900357000004")
            .serialize()
            .unwrap();
        // Re-parsing with "1.1a" always selects the last-registered profile (fv20260101)
        let AnyMessage::Insrpt(m) = Platform::with_all_profiles().parse(&bytes1).unwrap() else {
            panic!()
        };
        assert_eq!(m.assoc_code(), "1.1a");
        assert!(m.sender().is_some());
        assert!(m.receiver().is_some());
    }
}

