    /// DTM+137 is emitted in format 303 (not 102) as required by the UTILTS MIG 1.1e.
    ///
    /// UTILTS uses the same format-303 convention as PRICAT, different from
    /// UTILMD/MSCONS which use format 102.
    #[test]
    fn utilts_dtm137_uses_format_303() {
        let bytes = UtiltsBuilder::new(Release::new("1.1e"))
            .document_date("20241001")
            .add_vorgang(UtiltsVorgang::new("V001", 25001))
            .serialize()
            .unwrap();
        let raw = String::from_utf8(bytes).unwrap();
        assert!(
            raw.contains(":303'") || raw.contains(":303+"),
            "DTM+137 must use format 303, got: {raw}"
        );
        assert!(!raw.contains(":102'"), "DTM+137 must NOT use format 102");
    }

    /// Multiple Vorgänge in a single UTILTS message — PID of first Vorgang wins.
